import React from 'react';
import { Link, useStaticQuery } from 'gatsby';
import Img from "gatsby-image"
import useMediaQuery from "@material-ui/core/useMediaQuery"
import classnames from 'classnames';

export default function Footer() {
  const data = useStaticQuery(graphql`
    query {
      fbImage: file(relativePath: { eq: "facebook-logo.png" }) {
        childImageSharp {
          fluid(maxWidth: 150) {
            ...GatsbyImageSharpFluid
          }
        }
      }
      linkedinImage: file(relativePath: { eq: "linkedin.png" }) {
        childImageSharp {
          fluid(maxWidth: 150) {
            ...GatsbyImageSharpFluid
          }
        }
      }
      tbLogo: file(relativePath: { eq: "logo-neuro@2x.png" }) {
        childImageSharp {
          fluid {
            ...GatsbyImageSharpFluid
          }
        }
      }
    }
  `)
  let matchesDesktop = useMediaQuery("(min-width:600px)")
  return (
    <footer className={classnames({ desktop: matchesDesktop})}>
      <div className="footer-logo">
        <Img fluid={data.tbLogo.childImageSharp.fluid} style={{width: 150}} />
      </div>
      <div>
        <div className="social-links">
          <span>Siguenos en</span>
          <Img fluid={data.fbImage.childImageSharp.fluid} style={{ width: 30}} />
          <Img fluid={data.linkedinImage.childImageSharp.fluid} style={{ width: 30}} />
        </div>
        <nav>
          <span><Link to={`/cotiza`}>Contacto</Link></span>
          <span><Link to={`/productos`}>Productos</Link></span>
          <span><Link to={`/`}>Home</Link></span>
        </nav>
        <div className="disclaimer">
          <small>
            ThreeBond Mexico 2020. Todos los derechos reservados. <Link>Terminos y condicionales</Link> | <Link>Politica de privacidad</Link>
          </small>
        </div>
      </div>
    </footer>
  );
}

