import React from 'react';
import { Link } from 'gatsby';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import Paper from '@material-ui/core/Paper';

const ProductTableMobile = ({products, onSelectProduct}) => {
  let handleClick = (product) => () => {
    onSelectProduct(product);
  };
  return (
    <div className="products-table-container">
      {products.map(product => (
      <TableContainer component={Paper}>
        <Table onClick={handleClick(product)}>
          <TableHead>
            <TableRow>
              <TableCell>
                {product.name}
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            <TableRow>
              <TableCell>
                <b>Descripción</b>: {product.usages}<br />
                <b>Resistencia</b>: {product.resistencia || '-'}<br />
                <b>Propiedades</b>: {product.propiedades || '-'}<br />
                <b>Viscosidad (mPa-s)</b>: {product.viscosidad || '-'}<br />
                <b>Torsion de ruptura (N/m)</b>: {product.torsion || '-'}<br />
                <b>Rango de temperatura de operación</b>: {product.temperatura || '-'}<br />
                Apariencia: {product.apariencia || '-'}<br />
                TDS/SDS <FontAwesomeIcon icon={["fas", "file-download"]} style={{color:"#000000"}} />


              </TableCell>
            </TableRow>
          </TableBody>
        </Table>
      </TableContainer>
      ))}
    </div>
  );
};

const ProductTable = ({ products, onSelectProduct }) => {
  let handleClick = (product) => () => {
    onSelectProduct(product);
  };

  let matchMobile = useMediaQuery('(max-width: 599px)')
  if (matchMobile) return <ProductTableMobile products={products} onSelectProduct={onSelectProduct} />
  return(
    <TableContainer>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Nombre</TableCell>
            <TableCell>Descripción</TableCell>
            <TableCell>Resistencia</TableCell>
            <TableCell>Propiedades</TableCell>
            <TableCell>Viscosidad (mPa-s)</TableCell>
            <TableCell>Torsion de ruptura (N/m)</TableCell>
            <TableCell>Rango de temperatura de operación</TableCell>
            <TableCell>Apariencia</TableCell>
            <TableCell>TDS/SDS</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {
            products.map(product => (
              <TableRow onClick={handleClick(product)}>
                <TableCell>
                  <img src={product.image.childImageSharp.fluid.src} alt="product-image" />
                  <div className="product-name">
                    {product.name}
                    <Link to={`/productos/serie/${product.family.name}`}>Series {product.family.name}</Link>
                  </div>
                </TableCell>
                <TableCell>{product.usages}</TableCell>
                <TableCell>{product.resistencia || '-'}</TableCell>
                <TableCell>{product.propiedades || '-'}</TableCell>
                <TableCell>{product.viscosidad || '-'}</TableCell>
                <TableCell>{product.torsion || '-'}</TableCell>
                <TableCell>{product.temperatura || '-'}</TableCell>
                <TableCell>{product.apariencia || '-'}</TableCell>
                <TableCell><FontAwesomeIcon icon={["fas", "file-download"]} style={{color:"#000000"}} />
</TableCell>
              </TableRow>
            ))
          }
        </TableBody>
      </Table>
    </TableContainer>
  )
};

export default ProductTable;
