import React from 'react';
import { Link } from 'gatsby';
import { useProductState } from '../products-state';
import Breadcrumb from '../breadcrumb';
import TogglePanel from '../toggle-panel';
import useMediaQuery from '@material-ui/core/useMediaQuery';

let SideBar = (props) => {
  let { getMarkets, getFamilies, getSubtypes  } = useProductState();
  let matchMobile = useMediaQuery('(max-width: 599px)');

  let collapsedMarkets = matchMobile ? true : false;
  let collapsedProducts = true;
  let collapsedSeries = true;
  return (
    <section className="product__side-bar">
      <Breadcrumb path={props.path}/>
      <TogglePanel title='Mercados' collapsed={collapsedMarkets}>
        {getMarkets().map(market => <Link to={`/productos/${market.slug}`}>{market.name}</Link>)}
      </TogglePanel>
      <TogglePanel title='Productos' collapsed={collapsedProducts}>
        {getSubtypes().map(subtype => <Link to={`/productos/${subtype.slug}`}>{subtype.name}</Link>)}
      </TogglePanel>
      <TogglePanel title='Series' collapsed={collapsedSeries}>
        {getFamilies().map(family => <Link to={`/productos/serie/${family.slug}`}>{family.name}</Link>)}
      </TogglePanel>
    </section>
  );
}

export default SideBar;

